Planner updated.
Path: C:\Temp\Creating_Applications\admin\Test_Face\\.agent\planner.json

{
  "blockers": [],
  "features": [
    {
      "id": "f1",
      "status": "completed",
      "title": "Enrollment mode: scan named subfolders, extract single-face embeddings, average per person, persist fingerprints"
    },
    {
      "id": "f2",
      "status": "completed",
      "title": "Recognition mode: scan images, match against fingerprints, output JSON with names or 'unknown'"
    },
    {
      "id": "f3",
      "status": "completed",
      "title": "CLI with argparse: enroll and recognize subcommands"
    },
    {
      "id": "f4",
      "status": "pending",
      "title": "Unknown Face Discovery & Grouping: extract, group, and catalog unknown faces with persistent IDs"
    }
  ],
  "goal": "Build a Python CLI face-recognition app using InsightFace with enrollment and recognition modes",
  "goals": [
    {
      "id": "g1",
      "status": "completed",
      "title": "Project Setup and Dependencies"
    },
    {
      "id": "g2",
      "status": "completed",
      "title": "Core Face Processing Modules"
    },
    {
      "id": "g3",
      "status": "completed",
      "title": "CLI Interface and Integration"
    },
    {
      "id": "g4",
      "status": "completed",
      "title": "Testing and Verification"
    },
    {
      "id": "g5",
      "status": "in_progress",
      "title": "Unknown Face Discovery & Grouping Implementation"
    }
  ],
  "notes": [
    "InsightFace is already installed on the target system but must be listed in requirements.txt",
    "Folder structure for enrollment: root_folder/PersonName/image1.jpg, image2.png, etc.",
    "Images with 0 or 2+ faces are silently skipped during enrollment",
    "Recognition scans all images in subfolders of the input directory",
    "Matching uses cosine similarity with a configurable threshold (default ~0.6)",
    "Fingerprints stored as pickle file for efficiency"
  ],
  "project_type": "Coding / Software",
  "steps": [
    {
      "done_when": "Module provides estimate_yaw() and is_frontal_enough() with tests",
      "id": "u1",
      "output": "src/face_recognition/pose_filter.py",
      "status": "pending",
      "task": "Create pose_filter.py — yaw estimation from 2D/3D landmarks",
      "tool_hint": "project_filesystem write"
    },
    {
      "done_when": "Module provides crop_face() and save_face_crop() with bounds checking",
      "id": "u2",
      "output": "src/face_recognition/face_cropper.py",
      "status": "pending",
      "task": "Create face_cropper.py — crop face with margin and save thumbnail",
      "tool_hint": "project_filesystem write"
    },
    {
      "done_when": "Module provides base26 ID generation, match_or_create_unknown(), update fingerprint",
      "id": "u3",
      "output": "src/face_recognition/unknown_grouper.py",
      "status": "pending",
      "task": "Create unknown_grouper.py — ID generation, fingerprint matching, running average",
      "tool_hint": "project_filesystem write"
    },
    {
      "done_when": "recognize() accepts extract_unknowns params and processes unknown faces",
      "id": "u4",
      "output": "Updated face_recognizer.py",
      "status": "pending",
      "task": "Integrate unknown extraction into face_recognizer.py",
      "tool_hint": "project_filesystem edit"
    },
    {
      "done_when": "--extract-unknowns and related flags appear in recognize --help",
      "id": "u5",
      "output": "Updated main.py",
      "status": "pending",
      "task": "Add new CLI arguments to main.py for recognize subcommand",
      "tool_hint": "project_filesystem edit"
    },
    {
      "done_when": "Tests for ID generation, pose filter, cropper, grouper pass",
      "id": "u6",
      "output": "Updated tests/test_smoke.py",
      "status": "pending",
      "task": "Add unit tests for new modules",
      "tool_hint": "project_filesystem edit / powershell_execute"
    },
    {
      "done_when": "All tests pass including new ones",
      "id": "u7",
      "output": "Test results",
      "status": "pending",
      "task": "Run full smoke test suite",
      "tool_hint": "powershell_execute"
    },
    {
      "done_when": "README documents --extract-unknowns and related flags with examples",
      "id": "u8",
      "output": "Updated README.md",
      "status": "pending",
      "task": "Update README with unknown discovery documentation",
      "tool_hint": "project_filesystem edit"
    }
  ],
  "tool_hints": [
    "project_filesystem for file operations",
    "powershell_execute for testing and directory setup"
  ],
  "updated_at": "2026-05-09T06:39:00Z"
}

