function.arguments:
{"action":"write","content":""""Unknown face indexer — generates HTML gallery and JSON source tracking.

When unknown face extraction is enabled, this module creates:
1. `unknown_results.json` — maps each extracted face crop back to its source image,
   bounding box, pose angle, and group ID.
2. `index.html` — a self-contained HTML gallery for visual review and labeling.
"""

import json
import logging
from pathlib import Path
from typing import Any, Dict, List
from datetime import datetime

logger = logging.getLogger(__name__)


def _html_escape(text: str) -> str:
    """Escape HTML special characters."""
    return (
        text.replace("\u0026", "\u0026amp;")
        .replace("\u003c", "\u0026lt;")
        .replace("\u003e", "\u0026gt;")
        .replace('"', "\u0026quot;")
    )


def build_unknown_results(
    unknown_records: List[Dict[str, Any]],
) -> Dict[str, Any]:
    """Build the unknown_results.json data structure from extraction records.

    Args:
        unknown_records: List of dicts, each with keys:
            unknown_id, crop_path, source_image, bbox, pose_yaw, confidence

    Returns:
        Nested dict ready for JSON serialization.
    """
    groups: Dict[str, List[Dict[str, Any]]] = {}
    for rec in unknown_records:
        uid = rec["unknown_id"]
        groups.setdefault(uid, []).append(
            {
                "crop_path": rec["crop_path"],
                "source_image": rec["source_image"],
                "bbox": rec["bbox"],
                "pose_yaw": round(rec["pose_yaw"], 1) if rec.get("pose_yaw") is not None else None,
                "confidence": round(rec["confidence"], 4) if rec.get("confidence") is not None else 0.0,
            }
        )

    return {
        "generated_at": datetime.now().isoformat(),
        "total_groups": len(groups),
        "total_faces": len(unknown_records),
        "groups": {uid: {"faces": faces} for uid, faces in groups.items()},
    }


def save_unknown_results(
    data: Dict[str, Any],
    output_dir: Path,
) -> Path:
    """Save unknown_results.json to the unknown output directory.

    Args:
        data: Data structure from build_unknown_results().
        output_dir: Root directory for unknown face output.

    Returns:
        Path to the saved file.
    """
    path = Path(output_dir) / "unknown_results.json"
    path.parent.mkdir(parents=True, exist_ok=True)
    with open(path, "w", encoding="utf-8") as f:
        json.dump(data, f, indent=2, ensure_ascii=False)
    logger.info("Saved unknown results: %s", path)
    return path


def generate_html_index(
    data: Dict[str, Any],
    output_dir: Path,
) -> Path:
    """Generate a self-contained HTML gallery for visual review.

    Args:
        data: Data structure from build_unknown_results().
        output_dir: Root directory for unknown face output.

    Returns:
        Path to the saved index.html.
    """
    path = Path(output_dir) / "index.html"
    path.parent.mkdir(parents=True, exist_ok=True)

    groups = data.get("groups", {})
    total_groups = data.get("total_groups", 0)
    total_faces = data.get("total_faces", 0)
    generated_at = data.get("generated_at", "")

    # Build HTML body
    body_parts: List[str] = []
    body_parts.append(
        f"""
    <header>
      <h1>🔍 Unknown Face Discovery</h1>
      <p class="meta">
        {total_groups} group(s) · {total_faces} face(s) · Generated {generated_at}
      </p>
    </header>
"""
    )

    for uid in sorted(groups.keys()):
        group = groups[uid]
        faces = group.get("faces", [])
        face_count = len(faces)

        body_parts.append(f'    <section class="group">')
        body_parts.append(
            f'      <div class="group-header">'
            f'        <span class="group-id">{uid}</span>'
            f'        <span class="group-count">{face_count} face(s)</span>'
            f'        <input type="text" class="group-label" placeholder="Label this person..." data-id="{uid}">'
            f'      </div>'
        )
        body_parts.append('      <div class="gallery">')

        for face in faces:
            crop_rel = face["crop_path"]
            src = _html_escape(str(face["source_image"]))
            bbox = face.get("bbox", [])
            yaw = face.get("pose_yaw")
            yaw_str = f"{yaw:.1f}°" if yaw is not None else "N/A"

            body_parts.append(
                f'        <div class="card">'
                f'          <img src="{_html_escape(crop_rel)}" alt="Face {uid}" loading="lazy">'
                f'          <div class="card-info">'
                f'            <div class="info-row"><strong>Source:</strong> {src}</div>'
                f'            <div class="info-row"><strong>BBox:</strong> {bbox}</div>'
                f'            <div class="info-row"><strong>Yaw:</strong> {yaw_str}</div>'
                f'          </div>'
                f'        </div>'
            )

        body_parts.append("      </div>")
        body_parts.append("    </section>")

    html = f"""\u003c!DOCTYPE html>
<html lang="en">
<head>
  <meta charset="UTF-8">
  <meta name="viewport" content="width=device-width, initial-scale=1.0">
  <title>Unknown Face Discovery</title>
  <style>
    :root {{
      --bg: #f5f5f5;
      --card-bg: #fff;
      --text: #333;
      --accent: #4a90d9;
      --border: #ddd;
      --radius: 8px;
      --shadow: 0 2px 8px rgba(0,0,0,0.08);
    }}
    * {{ box-sizing: border-box; margin: 0; padding: 0; }}
    body {{
      font-family: -apple-system, BlinkMacSystemFont, "Segoe UI", Roboto, sans-serif;
      background: var(--bg);
      color: var(--text);
      line-height: 1.5;
      padding: 20px;
    }}
    header {{
      text-align: center;
      margin-bottom: 30px;
    }}
    header h1 {{ font-size: 1.8rem; margin-bottom: 8px; }}
    header .meta {{ color: #666; font-size: 0.9rem; }}
    .group {{
      background: var(--card-bg);
      border-radius: var(--radius);
      box-shadow: var(--shadow);
      margin-bottom: 24px;
      overflow: hidden;
    }}
    .group-header {{
      display: flex;
      align-items: center;
      gap: 12px;
      padding: 14px 18px;
      background: linear-gradient(135deg, var(--accent), #357abd);
      color: #fff;
    }}
    .group-id {{
      font-size: 1.3rem;
      font-weight: 700;
      min-width: 50px;
    }}
    .group-count {{
      font-size: 0.85rem;
      opacity: 0.9;
      flex: 1;
    }}
    .group-label {{
      padding: 6px 10px;
      border: 1px solid rgba(255,255,255,0.4);
      border-radius: 4px;
      background: rgba(255,255,255,0.15);
      color: #fff;
      font-size: 0.9rem;
      min-width: 160px;
    }}
    .group-label::placeholder {{ color: rgba(255,255,255,0.6); }}
    .gallery {{
      display: grid;
      grid-template-columns: repeat(auto-fill, minmax(160px, 1fr));
      gap: 14px;
      padding: 18px;
    }}
    .card {{
      background: var(--card-bg);
      border: 1px solid var(--border);
      border-radius: var(--radius);
      overflow: hidden;
      transition: transform 0.15s, box-shadow 0.15s;
    }}
    .card:hover {{
      transform: translateY(-3px);
      box-shadow: 0 4px 16px rgba(0,0,0,0.12);
    }}
    .card img {{
      width: 100%;
      height: 160px;
      object-fit: cover;
      display: block;
    }}
    .card-info {{
      padding: 10px 12px;
      font-size: 0.78rem;
      color: #555;
    }}
    .info-row {{
      margin-bottom: 4px;
      word-break: break-all;
    }}
    .info-row strong {{ color: #333; }}
    @media (max-width: 480px) {{
      .gallery {{ grid-template-columns: repeat(2, 1fr); }}
      .group-header {{ flex-wrap: wrap; }}
    }}
  </style>
</head>
<body>
{''.join(body_parts)}
  <script>
    // Save labels to localStorage so they persist across refreshes
    document.querySelectorAll('.group-label').forEach(input => {{
      const id = input.dataset.id;
      const saved = localStorage.getItem('label_' + id);
      if (saved) input.value = saved;
      input.addEventListener('input', e => {{
        localStorage.setItem('label_' + id, e.target.value);
      }});
    }});
  </script>
</body>
</html>"""

    with open(path, "w", encoding="utf-8") as f:
        f.write(html)
    logger.info("Saved HTML index: %s", path)
    return path
","path":"src/face_recognition/unknown_indexer.py"}

