{"change_reason":"New module for disk-backed embedding cache to handle millions of images per person without RAM blowup","change_summary":"EmbeddingCache streams embeddings to memory-mapped temp files, supports chunked iteration for outlier detection, and computes mean/similarities with bounded RAM. Auto-cleans temp files on exit.","content":"class EmbeddingCache:
    """Stream embeddings to disk and process them in bounded memory."""
    def __init__(self, embedding_dim: int = EMBEDDING_DIM) -> None:
        self.embedding_dim = embedding_dim
        self._count = 0
        self._temp_file: Optional[Path] = None
        self._mmap: Optional[np.memmap] = None
        self._closed = False
        fd, path = tempfile.mkstemp(suffix=".npy", prefix="embeddings_")
        self._temp_file = Path(path)
        initial_capacity = 64
        self._mmap = np.memmap(str(self._temp_file), dtype=EMBEDDING_DTYPE, mode="w+", shape=(initial_capacity, embedding_dim))
        self._capacity = initial_capacity
        atexit.register(self.cleanup)

    def append(self, embedding: np.ndarray) -> None:
        if self._closed: raise RuntimeError("EmbeddingCache is closed")
        embedding = np.asarray(embedding, dtype=EMBEDDING_DTYPE).reshape(-1)
        self._ensure_capacity(self._count + 1)
        self._mmap[self._count] = embedding
        self._count += 1
        self._mmap.flush()

    def chunks(self, chunk_size: int) -> Iterator[np.ndarray]:
        for start in range(0, self._count, chunk_size):
            end = min(start + chunk_size, self._count)
            yield np.array(self._mmap[start:end])

    def mean(self) -> np.ndarray:
        total = np.zeros(self.embedding_dim, dtype=np.float64)
        for chunk in self.chunks(4096):
            total += chunk.sum(axis=0)
        return (total / self._count).astype(EMBEDDING_DTYPE)

    def cosine_similarities_to(self, reference: np.ndarray) -> np.ndarray:
        reference = np.asarray(reference, dtype=np.float64)
        ref_norm = np.linalg.norm(reference)
        if ref_norm > 0: reference = reference / ref_norm
        similarities = np.empty(self._count, dtype=np.float64)
        idx = 0
        for chunk in self.chunks(4096):
            chunk_norms = np.linalg.norm(chunk, axis=1, keepdims=True)
            chunk_norms[chunk_norms == 0] = 1.0
            normalized = chunk / chunk_norms
            sims = normalized @ reference
            similarities[idx:idx+len(sims)] = sims
            idx += len(sims)
        return similarities.astype(np.float32)

    def cleanup(self) -> None:
        if self._closed: return
        self._closed = True
        if self._mmap is not None:
            try:
                self._mmap.flush()
                del self._mmap
                self._mmap = None
            except Exception: pass
        if self._temp_file is not None and self._temp_file.exists():
            for _ in range(5):
                try:
                    self._temp_file.unlink()
                    break
                except PermissionError:
                    import time; time.sleep(0.05)
            self._temp_file = None
        try: atexit.unregister(self.cleanup)
        except Exception: pass","file_path":"src/face_recognition/embedding_cache.py","kind":"class_summary","language":"python","reference_id":"face_recognition_cli","reference_name":"Face Recognition CLI","reference_type":"project","summary":"Disk-backed embedding cache that streams face embeddings to memory-mapped temp files. Keeps per-person RAM bounded to O(chunk_size) regardless of folder size. Supports chunked mean computation and cosine similarity calculation for outlier detection.","symbol":"EmbeddingCache","symbol_kind":"class"}

{"change_reason":"New SQLite-backed fingerprint store to replace monolithic pickle for millions of people","change_summary":"FingerprintDB uses SQLite with BLOB storage for embeddings. Supports insert/update/get/delete, batch operations, streaming iteration without loading all into RAM, and pickle migration.","content":"class FingerprintDB:
    """SQLite-backed fingerprint store."""
    def __init__(self, path: Path, embedding_dim: int = 512) -> None:
        self.path = Path(path)
        self.embedding_dim = embedding_dim
        self._conn: Optional[sqlite3.Connection] = None
        self._ensure_db()

    def _embedding_to_blob(self, embedding: np.ndarray) -> bytes:
        embedding = np.asarray(embedding, dtype=np.float32).reshape(-1)
        dim = embedding.shape[0]
        header = struct.pack("<H", dim)
        return header + embedding.tobytes()

    def _blob_to_embedding(self, blob: bytes) -> np.ndarray:
        dim = struct.unpack("<H", blob[:2])[0]
        return np.frombuffer(blob[2:], dtype=np.float32).reshape(dim)

    def insert(self, name: str, embedding: np.ndarray) -> None:
        blob = self._embedding_to_blob(embedding)
        self._conn.execute("INSERT INTO fingerprints (name, embedding) VALUES (?, ?) ON CONFLICT(name) DO UPDATE SET embedding=excluded.embedding, updated_at=CURRENT_TIMESTAMP", (name, blob))
        self._conn.commit()

    def insert_many(self, items: List[Tuple[str, np.ndarray]]) -> None:
        blobs = [(name, self._embedding_to_blob(emb)) for name, emb in items]
        self._conn.executemany("INSERT INTO fingerprints (name, embedding) VALUES (?, ?) ON CONFLICT(name) DO UPDATE SET embedding=excluded.embedding, updated_at=CURRENT_TIMESTAMP", blobs)
        self._conn.commit()

    def get(self, name: str) -> Optional[np.ndarray]:
        row = self._conn.execute("SELECT name, embedding FROM fingerprints WHERE name = ?", (name,)).fetchone()
        return self._blob_to_embedding(row[1]) if row else None

    def iter_all(self) -> Iterator[Tuple[str, np.ndarray]]:
        cursor = self._conn.execute("SELECT name, embedding FROM fingerprints")
        for row in cursor:
            yield row[0], self._blob_to_embedding(row[1])

    def get_all(self) -> Dict[str, np.ndarray]:
        return {name: emb for name, emb in self.iter_all()}

    def count(self) -> int:
        row = self._conn.execute("SELECT COUNT(*) FROM fingerprints").fetchone()
        return row[0] if row else 0

    @classmethod
    def from_pickle(cls, pickle_path: Path, db_path: Path) -> "FingerprintDB":
        with open(pickle_path, "rb") as f:
            data = pickle.load(f)
        db = cls(db_path)
        db.insert_many(list(data.items()))
        return db","file_path":"src/face_recognition/fingerprint_db.py","kind":"class_summary","language":"python","reference_id":"face_recognition_cli","reference_name":"Face Recognition CLI","reference_type":"project","summary":"SQLite-backed fingerprint store replacing monolithic pickle. Stores embeddings as compact BLOBs with uint16 header + float32 data. Supports incremental insert/update, batch operations, streaming iteration, and pickle migration. Keeps RAM bounded for millions of people.","symbol":"FingerprintDB","symbol_kind":"class"}
